import React from 'react';
import { motion, useViewportScroll, useTransform } from 'framer-motion';

interface MonolithGalleryProps {
  images: string[];
}

function MonolithItem({ src, idx }: { src: string; idx: number }) {
  const { scrollY } = useViewportScroll();
  const y = useTransform(scrollY, [0, 1000], [0, -100 * (idx + 1)]);

  return (
    <div className="monolith-item relative overflow-hidden glass rounded-xl h-[600px]">
      <motion.img
        src={src}
        className="absolute inset-0 w-full h-full object-cover"
        style={{ y }}
        alt="gallery"
      />
    </div>
  );
}

const MonolithGallery: React.FC<MonolithGalleryProps> = ({ images }) => {
  return (
    <div className="monolith-gallery grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-8 py-16">
      {images.map((src, idx) => (
        <MonolithItem key={`${src}-${idx}`} src={src} idx={idx} />
      ))}
    </div>
  );
};

export default MonolithGallery;
